import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as l,c as p,f as c,a as s,e,b as i,d as t}from"./app-65dc096f.js";const d={},r=s("blockquote",null,[s("p",null,"Project Setup & Simple Test")],-1),g=s("h1",{id:"setup",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#setup","aria-hidden":"true"},"#"),e(" Setup")],-1),u=s("code",null,"UCB",-1),h=s("code",null,"PKU",-1),B={href:"https://alfredthiel.gitbook.io/pintosbook/getting-started/environment-setup",target:"_blank",rel:"noopener noreferrer"},y=t(`<blockquote><p>由于本人不喜欢 <code>Virtual Box</code> ，所以这里还是选择了使用 <code>Docker</code> 构建（主要是不想下载，已经用了 <code>Linux</code> 居然还要用内存去开虚拟机……</p></blockquote><p>运行命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">run</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pkuflyingpig/pintos</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">bash</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>等待下载完成并运行，输入 <code>ls</code> ，看见 <code>toolchain</code> 文件夹说明下载成功</p><p>接着，克隆 <code>PKU</code> 的 <code>Pintos</code> 仓库（代码已经和 <code>CS 162</code> 不一样了，在文档中说这部分是 <code>PKU</code> 修改过的，看了一下 <code>UCB</code> 的实验似乎还有个人实验，这个 <code>pintos</code> 是一个小组实验）</p><p>运行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">git</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">clone</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">git@github.com:PKU-OS/pintos.git</span></span>
<span class="line"><span style="color:#61AFEF;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">run</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--rm</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--name</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pintos</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--mount</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">type=bind,source=</span><span style="color:#E06C75;">$pwd</span><span style="color:#98C379;">,target=/home/PKUOS/pintos</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pkuflyingpig/pintos</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">bash</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>由于下面这个命令可能会频繁使用，所以在 <code>.zshrc</code> 里写个 <code>alias</code>：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#C678DD;">alias</span><span style="color:#ABB2BF;"> </span><span style="color:#E06C75;">pintos-up</span><span style="color:#56B6C2;">=</span><span style="color:#98C379;">&quot;docker run -it --rm --name pintos --mount type=bind,source=</span><span style="color:#E06C75;">$pwd</span><span style="color:#98C379;">,target=/home/PKUOS/pintos pkuflyingpig/pintos&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>进入容器后，输入以下命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#56B6C2;">cd</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">pintos/src/threads</span></span>
<span class="line"><span style="color:#61AFEF;">make</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#56B6C2;">cd</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">build</span></span>
<span class="line"><span style="color:#61AFEF;">pintos</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果出现结果如下，则表示启动成功，环境已经安装好了</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230810233232.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>可以按 <code>&lt; Ctrl A &gt;</code> + <code>X</code>，表示先按下 <code>Ctrl</code> + <code>A</code>，再按下 <code>X</code> 来退出 <code>QEMU</code></p><h1 id="improve" tabindex="-1"><a class="header-anchor" href="#improve" aria-hidden="true">#</a> Improve</h1><p>可以发现 <code>pintos</code> 这个文件夹是没必要的（在可以通过 <code>VS Code</code> 直接 <code>ssh</code> 到容器的情况下），所以可以直接把源代码内置到容器之中，因此，我重新制作了一个镜像，并上传到了 <code>docker hub</code> 上</p><p>使用：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">run</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">virgil7/pintos</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">bash</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>下载后，通过 <code>VS Code</code> 中的 <code>ssh remote</code> 连接到容器中（如果不会用这个功能，请 STFW），如下所示：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230811145121.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><blockquote><p>如果显示了 <code>container is not started</code> 类似错误，运行 <code>docker start &lt;container-id&gt;</code> 启动容器即可</p></blockquote><p>这样，就不需要使用 <code>pintos-up</code> 这个命令来启动容器测试了，可以直接在容器内写代码测试</p><h1 id="l0-getting-real" tabindex="-1"><a class="header-anchor" href="#l0-getting-real" aria-hidden="true">#</a> L0 Getting Real</h1><h2 id="task-1-booting-pintos" tabindex="-1"><a class="header-anchor" href="#task-1-booting-pintos" aria-hidden="true">#</a> Task 1: Booting Pintos</h2><p>启动操作系统，按理来说是很简单的，如果搭建的教程是文档中的话，这一步不会出问题</p><p>但如果用的是我上传的 <code>docker</code>，也就是用 <code>vs code</code> 连接的话，在运行 <code>pintos --</code> 这一步时会出现：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230811155843.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>解决这个问题的方法也很简单，用电脑的终端就可以，例如：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230811155927.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>出现这个问题的原因大概有点头绪，应该是 <code>Makefile</code> 和 <code>perl</code> 脚本中对 <code>vga</code> 的定义写法的问题，留个坑之后再来解决这个问题。</p><p>上图为通过 <code>QEMU</code> 启动，此操作系统还可以通过 <code>Bochs</code> 启动，如图：</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230811160231.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h2 id="task-2-debugging" tabindex="-1"><a class="header-anchor" href="#task-2-debugging" aria-hidden="true">#</a> Task 2: Debugging</h2><p>运行命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">pintos</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--gdb</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后打开另外一个终端，输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">pintos-gdb</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">kernel.o</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>为了方便之后调试（主要是因为没有自动补全），所以写几个 <code>alias</code>：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#56B6C2;">echo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">&#39;alias pgdb=&quot;pintos-gdb&quot; \\n alias osstart=&quot;pintos --&quot; \\n alias osgdb=&quot;pintos --gdb --&quot; &#39;</span><span style="color:#ABB2BF;"> &gt;&gt; </span><span style="color:#98C379;">~/.bashrc</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,39);function m(b,v){const a=o("ExternalLinkIcon");return l(),p("div",null,[r,c("more"),g,s("p",null,[e("由于 "),u,e(" 的方法不对外校开放，开放的方法不是很能用= =，所以看了 "),h,e(" 的文档 "),s("a",B,[e("Environment Setup"),i(a)]),e(" ，进行构建。")]),y])}const F=n(d,[["render",m],["__file","PKU-OS-Setup.html.vue"]]);export{F as default};
